={{ (() => {
  const fuentes = [
    $json.body?.mensajeActual,
    $json.mensajeActual,
    $json.body?.mensaje,
    $json.mensaje,
    $json.mensajeCliente,
    $json.body?.chatInput,
    $json.chatInput,
    $json.body?.contextoConversacional,
    $json.contextoConversacional
  ]
    .map(valor => String(valor || "").trim())
    .filter(valor => valor !== "");

  const nombre =
    "([A-Za-zÁÉÍÓÚÜÑáéíóúüñ'-]+(?:\\s+[A-Za-zÁÉÍÓÚÜÑáéíóúüñ'-]+){0,3}?)";

  const limite =
    "(?=\\s*(?:" +
      "[.,;!?\\n]" +
      "|(?:y\\s+)?(?:mi\\s+)?(?:nombre|tel[eé]fono|celular|contacto)\\b" +
      "|(?:para\\s+)?(?:el\\s+)?(?:lunes|martes|mi[eé]rcoles|jueves|viernes|s[aá]bado|domingo)\\b" +
      "|(?:para\\s+)?(?:el\\s+)?\\d{1,2}\\s+de\\b" +
      "|hoy\\b" +
      "|ma[nñ]ana\\b" +
      "|pasado\\s+ma[nñ]ana\\b" +
      "|a\\s+las?\\s+\\d" +
      "|$" +
    "))";

  const patrones = [
    new RegExp(
      "\\bmi mascota es\\s+" +
      nombre +
      limite,
      "i"
    ),

    new RegExp(
      "\\bmi (?:perro|perra|gato|gata)\\s+" +
      "(?:(?:que\\s+)?se\\s+llama\\s+)?" +
      nombre +
      limite,
      "i"
    ),

    new RegExp(
      "\\b(?:perro|perra|gato|gata)\\s+llamad[oa]\\s+" +
      nombre +
      limite,
      "i"
    ),

    new RegExp(
      "\\bmascota\\s*:\\s*" +
      nombre +
      limite,
      "i"
    )
  ];

  for (const texto of fuentes) {
    for (const patron of patrones) {
      const coincidencia = texto.match(patron);

      if (coincidencia?.[1]) {
        return coincidencia[1].trim();
      }
    }
  }

  return String(
    $json.body?.nombreMascota ||
    $json.nombreMascota ||
    ""
  ).trim();
})() }}

