={{ (() => {
  const txt = String(
    $json.body?.chatInput ||
    $json.chatInput ||
    $json.body?.mensajeActual ||
    $json.mensajeActual ||
    $json.body?.mensaje ||
    $json.mensajeCliente ||
    ""
  );

  const porEtiqueta = txt.match(
    /(?:tel[eé]fono|celular|contacto|n[uú]mero)(?:\s+de\s+contacto)?\s*(?:es|:|=|-)?\s*(\+?56(?:[\s.-]*\d){9}|9(?:[\s.-]*\d){8})/i
  )?.[1];

  const porNumero = txt.match(
    /(\+?56(?:[\s.-]*\d){9})/
  )?.[1];

  const encontrado = porEtiqueta || porNumero;

  if (!encontrado) {
    return String(
      $json.body?.telefono ||
      $json.telefono ||
      ""
    ).trim();
  }

  let digitos = encontrado.replace(/\D/g, "");

  if (digitos.startsWith("56")) {
    digitos = digitos.slice(2);
  }

  if (
    digitos.length === 9 &&
    digitos.startsWith("9")
  ) {
    return `+56 9 ${digitos.slice(1, 5)} ${digitos.slice(5)}`;
  }

  return encontrado.trim();
})() }}

={{ (() => {
  const normalizar = (valor) =>
    String(valor || "")
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/\r/g, "");

  const mensajeActual = normalizar(
    $json.body?.mensajeActual ||
    $json.mensajeActual ||
    $json.body?.mensaje ||
    $json.mensaje ||
    $json.mensajeCliente ||
    ""
  );

  const contextoConversacional = normalizar(
    $json.body?.contextoConversacional ||
    $json.contextoConversacional ||
    ""
  );

  const chatInput = normalizar(
    $json.body?.chatInput ||
    $json.chatInput ||
    ""
  );

  const contextoCompleto = [
    contextoConversacional,
    chatInput
  ]
    .filter(Boolean)
    .join("\n");

  const detectarOpcion = (mensaje) => {
    const numero =
      mensaje.match(/^\s*([1-3])\s*[.)]?\s*$/) ||
      mensaje.match(
        /\b(?:opcion|alternativa)(?:\s+numero)?\s*([1-3])\b/
      ) ||
      mensaje.match(
        /\b(?:elijo|escojo|prefiero|quiero|selecciono)\s+(?:la\s+)?(?:opcion\s+)?([1-3])\b/
      );

    if (numero) {
      return Number(numero[1]);
    }

    const palabra = mensaje.match(
      /^\s*(?:(?:elijo|escojo|prefiero|quiero|selecciono)\s+)?(?:la\s+)?(primera|segunda|tercera|uno|dos|tres)(?:\s+opcion)?\s*[.!]?\s*$/
    );

    if (!palabra) {
      return null;
    }

    const equivalencias = {
      primera: 1,
      segunda: 2,
      tercera: 3,
      uno: 1,
      dos: 2,
      tres: 3
    };

    return equivalencias[palabra[1]] || null;
  };

  const contieneFechaYHora = (valor) => {
    const texto = normalizar(valor);

    const contieneFecha =
      /\b\d{1,2}\s+de\s+[a-z]+(?:\s+de\s+\d{4})?\b/.test(texto) ||
      /\bpasado\s+manana\b/.test(texto) ||
      /\bmanana\b/.test(texto) ||
      /\bhoy\b/.test(texto);

    const contieneHora =
      /\b(?:a\s+las?\s+)\d{1,2}(?:(?::\d{2})|\s+y\s+(?:media|cuarto|\d{1,2}))?\s*(?:de\s+la\s+)?(?:manana|tarde|noche)?\b/.test(texto) ||
      /\b\d{1,2}:\d{2}\b/.test(texto);

    return contieneFecha && contieneHora;
  };

  const buscarSolicitudAnterior = () => {
    const mensajesCliente = [];

    const patronCliente =
      /(?:^|\n)\s*(?:cliente|usuario|user):\s*([\s\S]*?)(?=\n\s*(?:(?:luna|asistente|assistant|cliente|usuario|user):)|$)/g;

    let coincidencia;

    while (
      (coincidencia = patronCliente.exec(contextoCompleto)) !== null
    ) {
      const mensaje = String(coincidencia[1] || "").trim();

      if (mensaje) {
        mensajesCliente.push(mensaje);
      }
    }

    for (let i = mensajesCliente.length - 1; i >= 0; i--) {
      if (contieneFechaYHora(mensajesCliente[i])) {
        return mensajesCliente[i];
      }
    }

    return "";
  };

  let texto = mensajeActual;

  const opcionSeleccionada = detectarOpcion(mensajeActual);

  if (opcionSeleccionada) {
    const patronOpcion = new RegExp(
      `(?:^|\\n)\\s*${opcionSeleccionada}\\s*[.)\\-:]\\s*([^\\n]+)`,
      "m"
    );

    const alternativaEncontrada =
      contextoCompleto.match(patronOpcion);

    if (!alternativaEncontrada?.[1]) {
      return "";
    }

    texto = alternativaEncontrada[1].trim();
  } else if (!contieneFechaYHora(mensajeActual)) {
    const solicitudAnterior = buscarSolicitudAnterior();

    if (!solicitudAnterior) {
      return "";
    }

    texto = solicitudAnterior;
  }

  const meses = {
    enero: 1,
    febrero: 2,
    marzo: 3,
    abril: 4,
    mayo: 5,
    junio: 6,
    julio: 7,
    agosto: 8,
    septiembre: 9,
    setiembre: 9,
    octubre: 10,
    noviembre: 11,
    diciembre: 12
  };

  const ahora = $now.setZone("America/Santiago");

  let fecha = ahora;

  const fechaExplicita = texto.match(
    /\b(\d{1,2})\s+de\s+([a-z]+)(?:\s+de\s+(\d{4}))?\b/
  );

  if (fechaExplicita) {
    const dia = Number(fechaExplicita[1]);
    const mes = meses[fechaExplicita[2]];
    const anio = fechaExplicita[3]
      ? Number(fechaExplicita[3])
      : ahora.year;

    if (!mes) {
      return "";
    }

    fecha = ahora.set({
      year: anio,
      month: mes,
      day: dia
    });
  } else if (texto.includes("pasado manana")) {
    fecha = ahora.plus({ days: 2 });
  } else if (texto.includes("manana")) {
    fecha = ahora.plus({ days: 1 });
  } else if (texto.includes("hoy")) {
    fecha = ahora;
  } else {
    return "";
  }

  const horaConPalabras = texto.match(
    /\b(?:a\s+las?\s+)(\d{1,2})(?:(?::(\d{2}))|\s+y\s+(media|cuarto|\d{1,2}))?\s*(?:de\s+la\s+)?(manana|tarde|noche)?\b/
  );

  const horaConDosPuntos = texto.match(
    /\b(\d{1,2}):(\d{2})\b/
  );

  let hora;
  let minuto;
  let periodo;

  if (horaConPalabras) {
    hora = Number(horaConPalabras[1]);

    if (horaConPalabras[2]) {
      minuto = Number(horaConPalabras[2]);
    } else if (horaConPalabras[3] === "media") {
      minuto = 30;
    } else if (horaConPalabras[3] === "cuarto") {
      minuto = 15;
    } else if (horaConPalabras[3]) {
      minuto = Number(horaConPalabras[3]);
    } else {
      minuto = 0;
    }

    periodo = horaConPalabras[4] || "";
  } else if (horaConDosPuntos) {
    hora = Number(horaConDosPuntos[1]);
    minuto = Number(horaConDosPuntos[2]);
    periodo = "";
  } else {
    return "";
  }

  if (minuto < 0 || minuto > 59) {
    return "";
  }

  if (
    (periodo === "tarde" || periodo === "noche") &&
    hora < 12
  ) {
    hora += 12;
  }

  if (periodo === "manana" && hora === 12) {
    hora = 0;
  }

  if (!periodo && hora >= 1 && hora <= 6) {
    hora += 12;
  }

  if (hora < 0 || hora > 23) {
    return "";
  }

  return fecha
    .set({
      hour: hora,
      minute: minuto,
      second: 0,
      millisecond: 0
    })
    .toISO();
})() }}

