={{ (() => {
  const txt = $json.body?.chatInput || $json.chatInput || "";

  const tutor = (txt.match(/Tutor:\s*([^\.]+)/i)?.[1] || "").trim();
  const mascota = (txt.match(/Mascota:\s*([^\.]+)/i)?.[1] || "").trim();
  const tipo = txt.toLowerCase().includes("consulta general") ? "consulta general" : "atención veterinaria";

  const normalizarTelefono = (valor) => {
    if (!valor) return "";

    let digitos = String(valor).replace(/\D/g, "");

    if (digitos.startsWith("56")) {
      digitos = digitos.slice(2);
    }

    if (digitos.length === 9 && digitos.startsWith("9")) {
      return `+56 ${digitos.slice(0, 1)} ${digitos.slice(1, 5)} ${digitos.slice(5)}`;
    }

    if (digitos.length === 8) {
      return `+56 9 ${digitos.slice(0, 4)} ${digitos.slice(4)}`;
    }

    return valor;
  };

  const porEtiqueta = txt.match(/Tel.{0,3}fono:\s*([+\d\s-]+)/i)?.[1];
  const porNumero = txt.match(/(?:\+?56)?\s*9?\s*\d{4}\s*\d{4}/)?.[0];
  const telefono = normalizarTelefono(porEtiqueta || porNumero || "");

  return `Tutor: ${tutor || "sin informar"}. Mascota: ${mascota || "sin informar"}. Tipo de atención: ${tipo}. Teléfono: ${telefono || "sin informar"}. Solicitud recibida por VetAtiende AI.`;
})() }}

