={{ (() => {
  const txt = $json.body?.chatInput 
    || $json.chatInput 
    || $json.mensajeCliente 
    || $json.situacionReportada 
    || $json.textoUrgencia 
    || "";

  const limpiar = (valor) => String(valor || "").trim();

  const normalizarTelefono = (valor) => {
    if (!valor) return "";

    let digitos = String(valor).replace(/\D/g, "");

    if (digitos.startsWith("56")) {
      digitos = digitos.slice(2);
    }

    if (digitos.length === 9 && digitos.startsWith("9")) {
      return `+56 ${digitos.slice(0, 1)} ${digitos.slice(1, 5)} ${digitos.slice(5)}`;
    }

    if (digitos.length === 8) {
      return `+56 9 ${digitos.slice(0, 4)} ${digitos.slice(4)}`;
    }

    return limpiar(valor);
  };

  const recortarTutor = (valor) => limpiar(
    String(valor || "")
      .replace(/\s+(mi\s+)?(perro|perra|perrito|perrita|cachorro|gato|gata|gatito|gatita|mascota)\b.*$/i, "")
  );

  const tutorPorEtiqueta = txt.match(/Tutor:\s*([^\.]+)/i)?.[1];

  const tutorPorSoy = recortarTutor(
    txt.match(/\bsoy\s+([^.,;\n]+)/i)?.[1]
  );

  const tutorPorNombre = recortarTutor(
    txt.match(/\b(?:mi nombre es|me llamo)\s+([^.,;\n]+)/i)?.[1]
  );

  const telefonoPorEtiqueta = txt.match(/Tel.{0,3}fono:\s*([+\d\s-]+)/i)?.[1];
  const telefonoPorNumero = txt.match(/(?:\+?56)?\s*9?\s*\d{4}\s*\d{4}/)?.[0];

  const mascotaPorEtiqueta = txt.match(/Mascota:\s*([^\.]+)/i)?.[1];

  const mascotaPorFrase = txt.match(
    /\b(?:mi\s+)?(?:perro|perrita|cachorro|gato|gatita|gatito|mascota)\s+([^\s\.,]+)/i
  )?.[1];

  const textoMinuscula = txt.toLowerCase();

  const tipoMascotaDetectada = (() => {
    if (textoMinuscula.includes("perro") || textoMinuscula.includes("perrita") || textoMinuscula.includes("cachorro")) return "perro";
    if (textoMinuscula.includes("gato") || textoMinuscula.includes("gatita") || textoMinuscula.includes("gatito")) return "gato";
    return "";
  })();

  const telefonoNormalizado = normalizarTelefono(
    $json.telefono 
    || $json.body?.telefono 
    || telefonoPorEtiqueta 
    || telefonoPorNumero 
    || ""
  );

  return {
    fecha_registro: $now.toISO(),

    canal_origen: $json.canalOrigen 
      || $json.canal_origen 
      || $json.body?.canalOrigen 
      || $json.body?.canal_origen
      || "flujo_publico_lab010",

    nombre_tutor: limpiar(
      $json.nombreTutor 
      || $json.nombre_tutor 
      || $json.body?.nombreTutor 
      || tutorPorEtiqueta
      || tutorPorNombre
      || tutorPorSoy
      || ""
    ),

    telefono: telefonoNormalizado ? "'" + telefonoNormalizado : "",

    nombre_mascota: limpiar(
      $json.nombreMascota 
      || $json.nombre_mascota 
      || $json.body?.nombreMascota 
      || mascotaPorEtiqueta 
      || mascotaPorFrase 
      || ""
    ),

    tipo_mascota: limpiar(
      $json.tipoMascota 
      || $json.tipo_mascota 
      || $json.body?.tipoMascota 
      || tipoMascotaDetectada 
      || ""
    ),

    situacion_reportada: limpiar(txt),

    tipo_urgencia: $json.tipoUrgencia 
      || $json.tipo_urgencia 
      || "urgencia_detectada",

    respuesta_luna: "Esto puede ser una urgencia veterinaria. Contacta de inmediato a la clínica o acude a atención veterinaria presencial. No esperes una confirmación de agenda para este caso.",

    estado_gestion: "registrada_pendiente_aviso",

    canal_aviso: "telegram_interno"
  };
})() }}

