const items = $input.all();

const DURACION_MINUTOS = 30;
const DIAS_A_BUSCAR = 7;
const TIMEZONE = "America/Santiago";

const feriados = [
  "2026-01-01",
  "2026-05-01",
  "2026-09-18",
  "2026-09-19",
  "2026-12-25"
];

const nombresDias = [
  "domingo",
  "lunes",
  "martes",
  "miércoles",
  "jueves",
  "viernes",
  "sábado"
];

const nombresMeses = [
  "enero",
  "febrero",
  "marzo",
  "abril",
  "mayo",
  "junio",
  "julio",
  "agosto",
  "septiembre",
  "octubre",
  "noviembre",
  "diciembre"
];

const meses = {
  enero: 1,
  febrero: 2,
  marzo: 3,
  abril: 4,
  mayo: 5,
  junio: 6,
  julio: 7,
  agosto: 8,
  septiembre: 9,
  setiembre: 9,
  octubre: 10,
  noviembre: 11,
  diciembre: 12
};

const diasSemanaTexto = {
  lunes: 1,
  martes: 2,
  miercoles: 3,
  jueves: 4,
  viernes: 5,
  sabado: 6,
  domingo: 0
};

function normalizarTexto(valor) {
  return String(valor || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function getChileParts(date) {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: TIMEZONE,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  }).formatToParts(date);

  const obj = {};

  for (const part of parts) {
    obj[part.type] = part.value;
  }

  return {
    year: Number(obj.year),
    month: Number(obj.month),
    day: Number(obj.day),
    hour: Number(obj.hour),
    minute: Number(obj.minute),
    date: `${obj.year}-${obj.month}-${obj.day}`
  };
}

function addDaysToLocalDate(dateString, days) {
  const [year, month, day] = dateString
    .split("-")
    .map(Number);

  const date = new Date(
    Date.UTC(
      year,
      month - 1,
      day + days,
      12,
      0,
      0
    )
  );

  const parts = getChileParts(date);

  return parts.date;
}

function getDayOfWeek(dateString) {
  const [year, month, day] = dateString
    .split("-")
    .map(Number);

  return new Date(
    Date.UTC(year, month - 1, day)
  ).getUTCDay();
}

function minutosAHora(minutos) {
  const hh = String(
    Math.floor(minutos / 60)
  ).padStart(2, "0");

  const mm = String(
    minutos % 60
  ).padStart(2, "0");

  return `${hh}:${mm}`;
}

function parseEvento(evento) {
  const inicio = evento.start?.dateTime;
  const fin = evento.end?.dateTime;

  if (!inicio || !fin) {
    return null;
  }

  const fechaInicio = inicio.slice(0, 10);
  const horaInicio = inicio.slice(11, 16);
  const horaFin = fin.slice(11, 16);

  const [h1, m1] = horaInicio
    .split(":")
    .map(Number);

  const [h2, m2] = horaFin
    .split(":")
    .map(Number);

  return {
    fecha: fechaInicio,
    inicioMinutos: h1 * 60 + m1,
    finMinutos: h2 * 60 + m2,
    resumen: evento.summary || ""
  };
}

function estaOcupado(
  fecha,
  inicioMinutos,
  finMinutos,
  eventosOcupados
) {
  return eventosOcupados.some((evento) => {
    if (evento.fecha !== fecha) {
      return false;
    }

    return (
      inicioMinutos < evento.finMinutos &&
      finMinutos > evento.inicioMinutos
    );
  });
}

function etiquetaFechaHora(fecha, hora) {
  const [year, month, day] = fecha
    .split("-")
    .map(Number);

  const diaSemana = getDayOfWeek(fecha);

  return (
    `${nombresDias[diaSemana]} ${day} de ` +
    `${nombresMeses[month - 1]} a las ${hora}`
  );
}

function etiquetaSoloFecha(fecha) {
  const [year, month, day] = fecha
    .split("-")
    .map(Number);

  const diaSemana = getDayOfWeek(fecha);

  return (
    `${nombresDias[diaSemana]} ${day} de ` +
    `${nombresMeses[month - 1]}`
  );
}

function obtenerTextoCliente() {
  const partes = [];

  try {
    const webhook =
      $("Webhook Solicitud Agenda").first().json;

    partes.push(
      webhook.body?.chatInput,
      webhook.body?.mensajeActual,
      webhook.body?.mensaje,
      webhook.chatInput,
      webhook.mensajeCliente,
      webhook.situacionReportada,
      webhook.observacionCliente
    );
  } catch (error) {}

  try {
    const preparar =
      $("Preparar Datos Agenda").first().json;

    partes.push(
      preparar.body?.chatInput,
      preparar.body?.mensajeActual,
      preparar.body?.mensaje,
      preparar.chatInput,
      preparar.mensajeCliente,
      preparar.situacionReportada,
      preparar.observacionCliente
    );
  } catch (error) {}

  return normalizarTexto(
    partes
      .filter(Boolean)
      .join(" ")
  );
}

function extraerFechaExplicita(
  txt,
  anioBase
) {
  const fechaTexto = txt.match(
    /\b(?:el\s+)?(\d{1,2})\s+de\s+([a-z]+)(?:\s+de\s+(\d{4}))?\b/
  );

  if (!fechaTexto) {
    return null;
  }

  const dia = String(
    Number(fechaTexto[1])
  ).padStart(2, "0");

  const mesNumero = meses[fechaTexto[2]];

  const anio = fechaTexto[3]
    ? Number(fechaTexto[3])
    : anioBase;

  if (!mesNumero) {
    return null;
  }

  const mes = String(
    mesNumero
  ).padStart(2, "0");

  return `${anio}-${mes}-${dia}`;
}

function obtenerProximoDiaSemana(
  hoyChile,
  diaObjetivo
) {
  for (
    let i = 0;
    i < DIAS_A_BUSCAR;
    i++
  ) {
    const fecha = addDaysToLocalDate(
      hoyChile,
      i
    );

    if (
      getDayOfWeek(fecha) ===
      diaObjetivo
    ) {
      return fecha;
    }
  }

  return null;
}

const ahoraChile =
  getChileParts(new Date());

const hoyChile =
  ahoraChile.date;

const minutoActualChile =
  ahoraChile.hour * 60 +
  ahoraChile.minute;

const textoCliente =
  obtenerTextoCliente();

const prefiereTarde =
  /\btarde\b/.test(textoCliente) ||
  /\bmas\s+tarde\b/.test(textoCliente);

const prefiereManana =
  /\ben\s+la\s+manana\b/.test(textoCliente) ||
  /\bpor\s+la\s+manana\b/.test(textoCliente) ||
  /\bde\s+la\s+manana\b/.test(textoCliente) ||
  /\bmas\s+temprano\b/.test(textoCliente) ||
  /\btemprano\b/.test(textoCliente);

const rechazaAlternativas =
  /\bno\s+me\s+sirven\b/.test(textoCliente) ||
  /\bno\s+me\s+sirve\b/.test(textoCliente) ||
  /\bno\s+me\s+acomoda\b/.test(textoCliente) ||
  /\bno\s+me\s+acomodan\b/.test(textoCliente) ||
  /\botra\s+hora\b/.test(textoCliente) ||
  /\botras\s+horas\b/.test(textoCliente) ||
  /\botro\s+horario\b/.test(textoCliente) ||
  /\botros\s+horarios\b/.test(textoCliente) ||
  /\botras\s+opciones\b/.test(textoCliente) ||
  /\bdame\s+otras\b/.test(textoCliente);

const diceMananaComoDia =
  /\bmanana\b/.test(textoCliente) &&
  !/\ben\s+la\s+manana\b/.test(textoCliente) &&
  !/\bpor\s+la\s+manana\b/.test(textoCliente) &&
  !/\bde\s+la\s+manana\b/.test(textoCliente);

let fechaPreferida = null;

if (/\bhoy\b/.test(textoCliente)) {
  fechaPreferida = hoyChile;
} else if (diceMananaComoDia) {
  fechaPreferida =
    addDaysToLocalDate(
      hoyChile,
      1
    );
} else {
  fechaPreferida =
    extraerFechaExplicita(
      textoCliente,
      ahoraChile.year
    );

  if (!fechaPreferida) {
    for (
      const [diaTexto, diaNumero]
      of Object.entries(diasSemanaTexto)
    ) {
      const patron =
        new RegExp(`\\b${diaTexto}\\b`);

      if (patron.test(textoCliente)) {
        fechaPreferida =
          obtenerProximoDiaSemana(
            hoyChile,
            diaNumero
          );

        break;
      }
    }
  }
}

const tienePreferencia =
  Boolean(fechaPreferida) ||
  prefiereTarde ||
  prefiereManana;

if (
  rechazaAlternativas &&
  !tienePreferencia
) {
  return [
    {
      json: {
        totalEventosOcupados:
          items.length,

        totalOpciones: 0,

        opcionesAgenda: [],

        mensajeOpcionesAgenda:
          "Entiendo. ¿Prefieres que revise opciones en la mañana, en la tarde o para un día específico?"
      }
    }
  ];
}

const eventosOcupados = items
  .map((item) =>
    parseEvento(item.json)
  )
  .filter(Boolean);

const opciones = [];

for (
  let i = 0;
  i < DIAS_A_BUSCAR;
  i++
) {
  const fecha =
    addDaysToLocalDate(
      hoyChile,
      i
    );

  if (
    fechaPreferida &&
    fecha !== fechaPreferida
  ) {
    continue;
  }

  const diaSemana =
    getDayOfWeek(fecha);

  if (
    feriados.includes(fecha)
  ) {
    continue;
  }

  if (diaSemana === 0) {
    continue;
  }

  let apertura;
  let cierre;

  if (
    diaSemana >= 1 &&
    diaSemana <= 5
  ) {
    apertura = 9 * 60;
    cierre = 18 * 60 + 30;
  } else if (
    diaSemana === 6
  ) {
    apertura = 10 * 60;
    cierre = 14 * 60;
  } else {
    continue;
  }

  let inicioBusqueda =
    apertura;

  let cierreBusqueda =
    cierre;

  if (prefiereTarde) {
    inicioBusqueda =
      Math.max(
        inicioBusqueda,
        14 * 60
      );
  }

  if (prefiereManana) {
    cierreBusqueda =
      Math.min(
        cierreBusqueda,
        12 * 60
      );
  }

  for (
    let inicio = inicioBusqueda;
    inicio + DURACION_MINUTOS <=
      cierreBusqueda;
    inicio += DURACION_MINUTOS
  ) {
    const fin =
      inicio + DURACION_MINUTOS;

    if (
      fecha === hoyChile &&
      inicio <= minutoActualChile
    ) {
      continue;
    }

    if (
      estaOcupado(
        fecha,
        inicio,
        fin,
        eventosOcupados
      )
    ) {
      continue;
    }

    const horaInicio =
      minutosAHora(inicio);

    const horaFin =
      minutosAHora(fin);

    opciones.push({
      numero:
        opciones.length + 1,

      fecha,

      hora:
        horaInicio,

      inicio:
        `${fecha}T${horaInicio}:00`,

      fin:
        `${fecha}T${horaFin}:00`,

      texto:
        etiquetaFechaHora(
          fecha,
          horaInicio
        )
    });

    if (
      opciones.length >= 3
    ) {
      break;
    }
  }

  if (
    opciones.length >= 3
  ) {
    break;
  }
}

let vieneDeHorarioOcupado =
  false;

try {
  vieneDeHorarioOcupado =
    $("Evaluar Disponibilidad Agenda")
      .first()
      .json
      .available === false;
} catch (error) {
  vieneDeHorarioOcupado =
    false;
}

let detallePreferencia = "";

if (fechaPreferida) {
  detallePreferencia +=
    ` para ${etiquetaSoloFecha(
      fechaPreferida
    )}`;
}

if (prefiereTarde) {
  detallePreferencia +=
    " en la tarde";
} else if (prefiereManana) {
  detallePreferencia +=
    " en la mañana";
}

/*
 * Recupera los datos que ya fueron
 * extraídos en Preparar Datos Agenda.
 */
let datosAgenda = {};

try {
  datosAgenda =
    $("Preparar Datos Agenda")
      .first()
      .json;
} catch (error) {
  datosAgenda = {};
}

const nombreTutor = String(
  datosAgenda.nombreTutor || ""
).trim();

const nombreMascota = String(
  datosAgenda.nombreMascota || ""
).trim();

const telefono = String(
  datosAgenda.telefono || ""
).trim();

const datosFaltantes = [];

if (!nombreTutor) {
  datosFaltantes.push(
    "nombre del tutor"
  );
}

if (!nombreMascota) {
  datosFaltantes.push(
    "nombre de la mascota"
  );
}

if (!telefono) {
  datosFaltantes.push(
    "teléfono de contacto"
  );
}

const tieneDatosMinimos =
  datosFaltantes.length === 0;

const solicitudDatosMinimos =
  tieneDatosMinimos
    ? ""
    : (
        "\n\nPara confirmar una hora necesito también estos datos mínimos:\n" +
        datosFaltantes
          .map(
            (dato) =>
              `- ${dato}`
          )
          .join("\n")
      );

let mensaje;

if (opciones.length > 0) {
  const ejemplo =
    opciones[1]?.texto ||
    opciones[0]?.texto;

  const cierreSeleccion =
    tieneDatosMinimos
      ? (
          "\n\n¿Cuál de estas opciones prefieres? " +
          "Puedes responder con el número o con la fecha y hora, " +
          `por ejemplo: ${ejemplo}.`
        )
      : (
          solicitudDatosMinimos +
          "\n\nPuedes responderme con la fecha y hora que prefieras " +
          "junto con esos datos, " +
          `por ejemplo: ${ejemplo}.`
        );

  if (vieneDeHorarioOcupado) {
    mensaje =
      "Ese horario no está disponible en la agenda de la clínica. " +
      `Tengo estas alternativas reales disponibles${detallePreferencia}:\n\n` +
      opciones
        .map(
          (opcion) =>
            `${opcion.numero}. ${opcion.texto}`
        )
        .join("\n") +
      cierreSeleccion;
  } else if (rechazaAlternativas) {
    mensaje =
      `Claro, revisé nuevas alternativas${detallePreferencia}. ` +
      "Tengo disponibles estas opciones:\n\n" +
      opciones
        .map(
          (opcion) =>
            `${opcion.numero}. ${opcion.texto}`
        )
        .join("\n") +
      cierreSeleccion;
  } else {
    mensaje =
      "Claro, puedo ayudarte a agendar una consulta general. " +
      "Tengo disponibles estas opciones:\n\n" +
      opciones
        .map(
          (opcion) =>
            `${opcion.numero}. ${opcion.texto}`
        )
        .join("\n") +
      cierreSeleccion;
  }
} else if (
  fechaPreferida ||
  prefiereTarde ||
  prefiereManana
) {
  mensaje =
    `Por ahora no encontré horarios disponibles${detallePreferencia} ` +
    "dentro del horario de atención. " +
    "Puedo revisar otra fecha u otro bloque horario " +
    "si me indicas una preferencia distinta.";
} else {
  mensaje =
    "Por ahora no encontré horarios disponibles para los próximos días " +
    "dentro del horario de atención. " +
    "Puedo revisar otra fecha si me indicas un día específico.";
}

return [
  {
    json: {
      totalEventosOcupados:
        eventosOcupados.length,

      totalOpciones:
        opciones.length,

      filtroAplicado: {
        fechaPreferida,
        prefiereTarde,
        prefiereManana,
        rechazaAlternativas
      },

      opcionesAgenda:
        opciones,

      datosAgenda: {
        nombreTutor,
        nombreMascota,
        telefono,
        datosFaltantes,
        tieneDatosMinimos
      },

      mensajeOpcionesAgenda:
        mensaje
    }
  }
];

