={{ (() => {
  const webhook = $("Webhook Solicitud Agenda").first().json;

  const texto = String(
    webhook.body?.mensajeActual ||
    webhook.mensajeActual ||
    ""
  )
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

  const meses = {
    enero: 1,
    febrero: 2,
    marzo: 3,
    abril: 4,
    mayo: 5,
    junio: 6,
    julio: 7,
    agosto: 8,
    septiembre: 9,
    setiembre: 9,
    octubre: 10,
    noviembre: 11,
    diciembre: 12
  };

  const ahora = $now.setZone("America/Santiago");

  let anio = ahora.year;
  let mes = ahora.month;
  let dia = ahora.day;

  const fechaExplicita = texto.match(
    /\b(\d{1,2})\s+de\s+([a-z]+)(?:\s+de\s+(\d{4}))?\b/
  );

  if (fechaExplicita) {
    dia = Number(fechaExplicita[1]);
    mes = meses[fechaExplicita[2]];
    anio = fechaExplicita[3]
      ? Number(fechaExplicita[3])
      : ahora.year;
  } else if (texto.includes("pasado manana")) {
    const fecha = ahora.plus({ days: 2 });
    anio = fecha.year;
    mes = fecha.month;
    dia = fecha.day;
  } else if (texto.includes("manana")) {
    const fecha = ahora.plus({ days: 1 });
    anio = fecha.year;
    mes = fecha.month;
    dia = fecha.day;
  } else if (texto.includes("hoy")) {
    anio = ahora.year;
    mes = ahora.month;
    dia = ahora.day;
  }

  const horaEncontrada =
    texto.match(
      /\b(?:a\s+las\s+|de\s+)(\d{1,2})(?::(\d{2}))?\s*(?:de\s+la\s+)?(manana|tarde|noche)?\b/
    ) ||
    texto.match(
      /\b(\d{1,2})(?::(\d{2}))?\s*(?:de\s+la\s+)?(manana|tarde|noche)?\b/
    );

  if (!horaEncontrada || !mes) return "";

  let hora = Number(horaEncontrada[1]);
  const minuto = Number(horaEncontrada[2] || 0);
  const periodo = horaEncontrada[3] || "";

  if ((periodo === "tarde" || periodo === "noche") && hora < 12) {
    hora += 12;
  }

  if (periodo === "manana" && hora === 12) {
    hora = 0;
  }

  if (!periodo && hora >= 1 && hora <= 6) {
    hora += 12;
  }

  return ahora
    .set({
      year: anio,
      month: mes,
      day: dia,
      hour: hora,
      minute: minuto,
      second: 0,
      millisecond: 0
    })
    .toISO();
})() }}

